// Get a module by its ID
var module = StelModuleMgr.getModule("ConstellationMgr");
if(module) {
    core.debug("ConstellationMgr module found");
    // Access module methods
    module.setFlagLines(true);
}

// Use the macro (standard approach in scripts)
var constMgr = GETSTELMODULE(ConstellationMgr);
if(constMgr) {
    constMgr.setFlagLabels(true);
}

// Suppress warning for optional plugin
var plugin = StelModuleMgr.getModule("Oculars", true);
if(!plugin) {
    core.debug("Oculars plugin is not loaded");
}

// Using silent macro version
var oculars = GETSTELMODULE_SILENT(Oculars);

// List all loaded modules
var allModules = StelModuleMgr.getAllModules();
core.debug("Total loaded modules: " + allModules.length);

// Print first 15 module names
for(var i = 0; i < Math.min(15, allModules.length); i++) {
    core.debug("Module #" + (i+1) + ": " + allModules[i].objectName);
}

// Find a specific module by name pattern
for(var j = 0; j < allModules.length; j++) {
    var name = allModules[j].objectName;
    if(name.indexOf("Star") >= 0) {
        core.debug("Star-related module found: " + name);
    }
}

// Check the draw order of modules
// Note: StelModule::ActionDraw = 0 in the enum
var drawOrder = StelModuleMgr.getCallOrders(0); // ActionDraw
core.debug("Modules in draw order:");
for(var i = 0; i < Math.min(10, drawOrder.length); i++) {
    core.debug(i + ": " + drawOrder[i].objectName);
}

// Load a plugin dynamically
var plugin = StelModuleMgr.loadPlugin("Oculars");
if(plugin) {
    core.debug("Oculars plugin loaded: " + plugin.objectName);
} else {
    core.debug("Failed to load Oculars plugin");
}

// Check if loaded and then access it
if(StelModuleMgr.isPluginLoaded("Oculars")) {
    var oculars = GETSTELMODULE(Oculars);
    // Use oculars methods...
}

// Unload all plugins to start fresh
StelModuleMgr.unloadAllPlugins();
core.debug("All plugins unloaded");

// Then load only specific plugins
StelModuleMgr.loadPlugin("Oculars");
core.debug("Only Oculars plugin is now loaded");

// Enable auto-loading of a plugin at startup
StelModuleMgr.setPluginLoadAtStartup("Oculars", true);
core.debug("Oculars plugin will load automatically on next startup");

// Disable auto-loading
StelModuleMgr.setPluginLoadAtStartup("Satellites", false);
core.debug("Satellites plugin will not load at startup");

// Check current plugins and their load status
var plugins = StelModuleMgr.getPluginsList();
for(var i = 0; i < plugins.length; i++) {
    core.debug(plugins[i].info.id + ": loadAtStartup=" + plugins[i].loadAtStartup + ", loaded=" + plugins[i].loaded);
}

// Check if a plugin is loaded before trying to access it
if(StelModuleMgr.isPluginLoaded("Oculars")) {
    var oculars = GETSTELMODULE(Oculars);
    core.debug("Oculars is loaded and ready");
} else {
    core.debug("Oculars plugin is not loaded, loading now...");
    StelModuleMgr.loadPlugin("Oculars");
}

// Check multiple plugins
var pluginList = ["Oculars", "Satellites", "RemoteControl", "TelescopeControl"];
for(var i = 0; i < pluginList.length; i++) {
    var loaded = StelModuleMgr.isPluginLoaded(pluginList[i]);
    core.debug(pluginList[i] + ": " + (loaded ? "loaded" : "not loaded"));
}

// List all available plugins with their status
var plugins = StelModuleMgr.getPluginsList();
core.debug("Available plugins: " + plugins.length);

for(var i = 0; i < plugins.length; i++) {
    var p = plugins[i];
    var info = p.info;
    core.debug("---");
    core.debug("ID: " + info.id);
    core.debug("Name: " + info.name);
    core.debug("Description: " + info.description);
    core.debug("Version: " + info.version);
    core.debug("Loaded: " + p.loaded);
    core.debug("Load at startup: " + p.loadAtStartup);
}

// Find all unloaded plugins
var unloadedPlugins = [];
for(var j = 0; j < plugins.length; j++) {
    if(!plugins[j].loaded) {
        unloadedPlugins.push(plugins[j].info.id);
    }
}
core.debug("Unloaded plugins: " + unloadedPlugins.join(", "));

// List all registered extensions
var extensions = StelModuleMgr.getExtensionList();
core.debug("Registered extensions: " + extensions.length);

for(var i = 0; i < extensions.length; i++) {
    core.debug("Extension #" + i + ": " + extensions[i].objectName);
}

// Load extensions for a specific plugin
var exts = StelModuleMgr.loadExtensions("RemoteControl");
if(exts.length > 0) {
    core.debug("Loaded " + exts.length + " extensions for RemoteControl");
    for(var i = 0; i < exts.length; i++) {
        core.debug("Extension: " + exts[i].objectName);
    }
} else {
    core.debug("No extensions found for RemoteControl");
}

// Get support info for a custom script
var supportInfo = StelModuleMgr.getStandardSupportLinksInfo("MyCustomScript");
core.debug("Support info: " + supportInfo);
// Output includes links to:
// - Google Groups forum
// - GitHub issues page

// Get extended info with developer documentation link
var extendedInfo = StelModuleMgr.getStandardSupportLinksInfo("MyPlugin", true);
core.debug("Extended support info generated");
